module top_module(
        input   wire        clk,
        input   wire        reset,
        input   wire[31:0]  next_pc_pc_reg_i,
        output  wire[31:0]  next_pc_pc_reg_o
    );reg [31:0] prev_pc_pc_reg;

    assign next_pc_pc_reg_o = prev_pc_pc_reg;

    always @(posedge clk or posedge reset)
    if (reset)
        prev_pc_pc_reg <= 31'b0;
    else
        prev_pc_pc_reg <= next_pc_pc_reg_i;

endmodule
